import { classNames } from ':helpers/classnames';
import React, { isValidElement } from 'react';
import { FloatingNavigationItemProps } from './FloatingNavigationItem.types';
import './FloatingNavigationItem.scss';

export const FloatingNavigationItem: React.FC<FloatingNavigationItemProps> = ({
	label,
	active,
	child,
	onClick,
	onKeyDown,
	children,
}) => {
	return (
		<>
			<div
				role="listitem"
				onClick={onClick}
				className={classNames(
					'dsb_floatingnav__item',
					active && 'dsb_floatingnav__item-active',
					child && 'dsb_floatingnav__item-child',
				)}
				tabIndex={0}
				onKeyDown={onKeyDown}
			>
				{label}
			</div>
			{active && children?.map(child => isValidElement(child) && React.cloneElement<any>(child, { child }))}
		</>
	);
};
